// modules/auth/lib/queries.ts
import { query } from '../db';

export async function getUserById(userId: string) {
  const result = await query('SELECT * FROM users WHERE id = $1', [userId]);
  return result.rows[0];
}

export async function getSessionByToken(token: string) {
  const result = await query('SELECT * FROM sessions WHERE token = $1', [token]);
  return result.rows[0];
}

// modules/auth/lib/transactions.ts
import { transaction } from '../db';
import { getUserById, getSessionByToken } from './queries';

export async function removeMemberFromTeam(teamId: string, userId: string) {
  await transaction(async (client) => {
    // Check if the user is the owner of the team
    const user = await getUserById(userId);
    if (user.role === 'owner') {
      throw new Error('Owner cannot be removed');
    }

    // Remove the user from the team
    await client.query('DELETE FROM team_members WHERE team_id = $1 AND user_id = $2', [teamId, userId]);

    // Unassign all tasks assigned to the user in the team
    await client.query('UPDATE tasks SET assignee_id = NULL WHERE team_id = $1 AND assignee_id = $2', [teamId, userId]);
  });
}

// modules/auth/routes/remove-member.ts
import { Router } from 'bun';
import { requireUser, getSession } from '../../lib/auth';
import { removeMemberFromTeam } from '../lib/transactions';

const router = new Router();

router.post('/auth/remove-member', async (req) => {
  const user = await requireUser(req);
  const session = await getSession(req);

  // Parse request body
  const { teamId, userId } = await parseBody<{ teamId: string; userId: string }>(req);

  // Remove member from team in a transaction
  try {
    await removeMemberFromTeam(teamId, userId);
    return new Response(JSON.stringify({ message: 'User removed successfully' }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 400 });
  }
});

export default router;

// modules/auth/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'auth',
  description: 'Handles user authentication, session management, and authorization utilities.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/auth/login',   auth: false },
      { method: 'POST', path: '/auth/logout',  auth: true },
      { method: 'GET',  path: '/auth/session', auth: true },
      { method: 'POST', path: '/auth/remove-member', auth: true },
    ],
    functions: ['requireUser', 'getSession', 'createSession', 'invalidateSession'],
    types: ['User', 'Session', 'AuthError'],
  },

  sideEffects: [
    'writes to: sessions table',
    'reads from: users table',
    'writes to: team_members table',
    'updates tasks table',
  ],

  invariants: [
    'A session must always be bound to exactly one user',
    'Expired sessions must never be returned as valid',
    'Logout must invalidate the session immediately',
    'Owner cannot be removed from a team',
    'All tasks assigned to a removed member must be unassigned',
  ],
});

